#!/usr/bin/env node
/**
 * check-no-inline-styles.mjs
 * ---------------------------------------------------------------------------
 * Anti-recidiva gate (Sprint 5 task 5.1 / #62). Catches any future PR that
 * re-introduces an inline `style="…"` attribute under `frontend/`, which
 * would silently re-break CSP enforce.
 *
 * Why
 * ---
 * After Sprint 5 task 5.1 the production CSP serves
 *   `style-src 'self'; style-src-attr 'none'`
 * which BLOCKS every inline `style="…"` attribute (whether literal in HTML,
 * or generated by JS via innerHTML — the resulting DOM attribute is
 * forbidden either way). A forgotten `style="margin:0"` becomes a runtime
 * stylesheet drop in production, not a build error. This gate brings the
 * detection forward to CI.
 *
 * Behaviour
 * ---------
 *   exit 0  → no `style="` substrings under frontend/ outside CSS comments
 *   exit 2  → at least one offending occurrence found
 *
 * Scope
 * -----
 *   Scans: `frontend/**\/*.html` and `frontend/**\/*.js`
 *   Skips: `frontend/assets/css/**` (CSS file body legitimately mentions
 *          `style="..."` in comments documenting the migration), and
 *          `frontend/assets/vendor/**` (third-party shipped as-is).
 *
 * Wired into
 * ----------
 *   `npm run check:no-inline-styles`
 *   `npm run build:check`
 */

import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');
const TARGET = path.join(ROOT, 'frontend');

const SKIP_DIRS = new Set(['css', 'vendor', 'fonts', 'icons']);
const ALLOWED_EXT = new Set(['.html', '.js']);

function* walk(dir) {
  const entries = fs.readdirSync(dir, { withFileTypes: true });
  for (const e of entries) {
    if (e.name.startsWith('.')) continue;
    const p = path.join(dir, e.name);
    if (e.isDirectory()) {
      if (SKIP_DIRS.has(e.name)) continue;
      yield* walk(p);
    } else if (e.isFile()) {
      const ext = path.extname(e.name);
      if (ALLOWED_EXT.has(ext)) yield p;
    }
  }
}

const TAG = '[check-no-inline-styles]';
const offenders = [];

for (const file of walk(TARGET)) {
  const body = fs.readFileSync(file, 'utf8');
  const lines = body.split('\n');
  for (let i = 0; i < lines.length; i += 1) {
    const line = lines[i];
    if (!line.includes('style="')) continue;
    offenders.push({
      file: path.relative(ROOT, file),
      line: i + 1,
      excerpt: line.trim().slice(0, 160),
    });
  }
}

if (offenders.length > 0) {
  console.error(`${TAG} FAIL — ${offenders.length} inline style="…" attribute(s) found.`);
  console.error(`${TAG} CSP enforce blocks these in production. Refactor to a CSS class.`);
  for (const o of offenders) {
    console.error(`${TAG}   ${o.file}:${o.line}  ${o.excerpt}`);
  }
  console.error(`${TAG} Common patterns and their utility classes are documented in`);
  console.error(`${TAG}   frontend/assets/css/app.css §12 (utilities) and §15 (semantic blocks).`);
  process.exit(2);
}

console.log(`${TAG} OK — no inline style="…" attributes under frontend/.`);
